// O(n*W) time, O(W) space (1D optimized)
function zeroOneKnapsack(profits, weights, capacity) {
  const dp = new Array(capacity + 1).fill(0);
  for (let i = 0; i < profits.length; i++) {
    // iterate right-to-left to prevent using same item twice
    for (let w = capacity; w >= weights[i]; w--) {
      dp[w] = Math.max(dp[w], profits[i] + dp[w - weights[i]]);
    }
  }
  return dp[capacity];
}
